CREATE OR REPLACE FUNCTION ods.fn_get_member_monthly_total(
    p_member_id BIGINT, p_year INT, p_month INT
) RETURNS NUMERIC AS $$
BEGIN
    RETURN COALESCE((
        SELECT SUM(amount) FROM ods.expense
        WHERE member_id = p_member_id
          AND EXTRACT(YEAR  FROM expense_date) = p_year
          AND EXTRACT(MONTH FROM expense_date) = p_month
    ), 0);
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION ods.fn_get_member_savings_rate(
    p_member_id BIGINT
) RETURNS NUMERIC AS $$
DECLARE
    v_income         NUMERIC;
    v_total_expenses NUMERIC;
BEGIN
    SELECT COALESCE(MAX(income), 0) INTO v_income
    FROM ods.savings_goal
    WHERE member_id = p_member_id AND status = 'ACTIVE';

    SELECT COALESCE(SUM(amount), 0) INTO v_total_expenses
    FROM ods.expense
    WHERE member_id  = p_member_id
      AND expense_date >= DATE_TRUNC('month', CURRENT_DATE);

    IF v_income = 0 THEN RETURN 0; END IF;
    RETURN ROUND(((v_income - v_total_expenses) / v_income) * 100, 2);
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION ods.fn_get_category_summary(
    p_member_id BIGINT
) RETURNS TABLE(category VARCHAR, total NUMERIC, percentage NUMERIC) AS $$
DECLARE v_grand_total NUMERIC;
BEGIN
    SELECT COALESCE(SUM(amount), 0) INTO v_grand_total
    FROM ods.expense WHERE member_id = p_member_id;

    RETURN QUERY
    SELECT e.category,
           SUM(e.amount) AS total,
           CASE WHEN v_grand_total = 0 THEN 0
                ELSE ROUND((SUM(e.amount) / v_grand_total) * 100, 2)
           END AS percentage
    FROM ods.expense e
    WHERE e.member_id = p_member_id
    GROUP BY e.category ORDER BY total DESC;
END;
$$ LANGUAGE plpgsql;
